patch:
--- a/register_file.v
+++ b/register_file.v
@@ -18,8 +18,8 @@ module register_file_wrapper (
   output [15:0] read_data
 );
   register_file rf_inst (
-    .write_addr(write_address[3:0]),
-    .write_data(write_value),
+    .write_addr(write_address[2:0]),
+    .write_data(write_value[15:0]),
     .read_addr(read_address[2:0]),
     .read_data(read_data)
   );

before_code:
module register_file (
  input [2:0] write_addr,
  input [15:0] write_data,
  input [2:0] read_addr,
  output [15:0] read_data
);
  reg [15:0] regs [7:0];
  always @(*) begin
    regs[write_addr] <= write_data;
  end
  assign read_data = regs[read_addr];
endmodule

module register_file_wrapper (
  input [3:0] write_address,
  input [31:0] write_value,
  input [2:0] read_address,
  output [15:0] read_data
);
  register_file rf_inst (
    .write_addr(write_address[3:0]),
    .write_data(write_value),
    .read_addr(read_address[2:0]),
    .read_data(read_data)
  );
endmodule

after_code:
module register_file (
  input [2:0] write_addr,
  input [15:0] write_data,
  input [2:0] read_addr,
  output [15:0] read_data
);
  reg [15:0] regs [7:0];
  always @(*) begin
    regs[write_addr] <= write_data;
  end
  assign read_data = regs[read_addr];
endmodule

module register_file_wrapper (
  input [3:0] write_address,
  input [31:0] write_value,
  input [2:0] read_address,
  output [15:0] read_data
);
  register_file rf_inst (
    .write_addr(write_address[2:0]),
    .write_data(write_value[15:0]),
    .read_addr(read_address[2:0]),
    .read_data(read_data)
  );
endmodule
